import { useState } from 'react';
import { getIngredients } from '../services/gemini';

function ChatBox({ onIngredientsFound }) {
  const [messages, setMessages] = useState([
    { role: 'bot', text: "Hi! Tell me what you'd like to cook and for how many people 🛒" }
  ]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {
    if (!input.trim()) return;
    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setLoading(true);

    try {
      const result = await getIngredients(userMsg);
      setMessages(prev => [...prev, { role: 'bot', text: result.reply }]);
      onIngredientsFound(result.ingredients);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'bot', text: 'Something went wrong, try again!' }]);
    }
    setLoading(false);
  };

  return (
    <div className="chatbox">
      <div className="messages">
        {messages.map((m, i) => (
          <div key={i} className={`msg ${m.role}`}>{m.text}</div>
        ))}
        {loading && <div className="msg bot">Finding ingredients...</div>}
      </div>
      <div className="input-row">
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && sendMessage()}
          placeholder="e.g. chocolate cake for 2 people"
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
}

export default ChatBox;
